import {
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  effect,
  input,
  viewChild,
} from '@angular/core';
import { Frame, VizMode } from '../core/models';

/** Confidence below this draws the cell faded to flag sparse coverage. */
const LOW_CONFIDENCE = 0.45;
const MIN_ALPHA = 0.28;

@Component({
  selector: 'app-heatmap-canvas',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  templateUrl: './heatmap-canvas.component.html',
  styleUrl: './heatmap-canvas.component.css',
})
export class HeatmapCanvasComponent {
  readonly frame = input<Frame | null>(null);
  readonly mode = input<VizMode>('absolute');

  private readonly canvasRef =
    viewChild<ElementRef<HTMLCanvasElement>>('canvas');

  // Domains for color mapping (°F).
  private readonly absoluteDomain = { min: -10, max: 110 };
  private readonly deviationDomain = { min: -20, max: 20 };

  constructor() {
    effect(() => {
      // Re-run whenever the frame or mode changes.
      const frame = this.frame();
      const mode = this.mode();
      const canvas = this.canvasRef()?.nativeElement;
      if (canvas) {
        this.draw(canvas, frame, mode);
      }
    });
  }

  /** Resolve the design-token color ramp from CSS custom properties. */
  private rampFor(mode: VizMode): string[] {
    const css = getComputedStyle(document.documentElement);
    const names =
      mode === 'absolute'
        ? ['--temp-c0', '--temp-c1', '--temp-c2', '--temp-c3', '--temp-c4', '--temp-c5', '--temp-c6']
        : ['--dev-cold', '--dev-cool', '--dev-mid', '--dev-warm', '--dev-hot'];
    return names.map((n) => css.getPropertyValue(n).trim() || '#888888');
  }

  private draw(canvas: HTMLCanvasElement, frame: Frame | null, mode: VizMode): void {
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpr = window.devicePixelRatio || 1;
    const cssW = canvas.clientWidth || 640;
    const cssH = canvas.clientHeight || 400;
    canvas.width = Math.floor(cssW * dpr);
    canvas.height = Math.floor(cssH * dpr);
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

    const bg = getComputedStyle(document.documentElement)
      .getPropertyValue('--color-canvas-bg')
      .trim() || '#0d1b2a';
    ctx.fillStyle = bg;
    ctx.fillRect(0, 0, cssW, cssH);

    if (!frame || frame.grid.length === 0) return;

    const { rows, cols, grid, confidence } = frame;
    const ramp = this.rampFor(mode);
    const domain = mode === 'absolute' ? this.absoluteDomain : this.deviationDomain;
    const cw = cssW / cols;
    const ch = cssH / rows;

    for (let r = 0; r < rows; r++) {
      for (let c = 0; c < cols; c++) {
        const idx = r * cols + c;
        const value = grid[idx];
        if (value === null || value === undefined) continue; // outside US mask

        const t = this.clamp01((value - domain.min) / (domain.max - domain.min));
        const color = this.sampleRamp(ramp, t);
        const conf = confidence[idx] ?? 1;
        const alpha = conf < LOW_CONFIDENCE ? MIN_ALPHA : 1;

        ctx.globalAlpha = alpha;
        ctx.fillStyle = color;
        // +0.6 overdraw removes hairline seams between cells.
        ctx.fillRect(c * cw, r * ch, cw + 0.6, ch + 0.6);
      }
    }
    ctx.globalAlpha = 1;
  }

  private sampleRamp(ramp: string[], t: number): string {
    if (ramp.length === 1) return ramp[0];
    const scaled = t * (ramp.length - 1);
    const i = Math.min(ramp.length - 2, Math.floor(scaled));
    const f = scaled - i;
    return this.lerpColor(ramp[i], ramp[i + 1], f);
  }

  private lerpColor(a: string, b: string, t: number): string {
    const ca = this.parseHex(a);
    const cb = this.parseHex(b);
    if (!ca || !cb) return a;
    const r = Math.round(ca[0] + (cb[0] - ca[0]) * t);
    const g = Math.round(ca[1] + (cb[1] - ca[1]) * t);
    const bl = Math.round(ca[2] + (cb[2] - ca[2]) * t);
    return `rgb(${r}, ${g}, ${bl})`;
  }

  private parseHex(hex: string): [number, number, number] | null {
    const m = hex.replace('#', '');
    if (m.length !== 6) return null;
    return [
      parseInt(m.slice(0, 2), 16),
      parseInt(m.slice(2, 4), 16),
      parseInt(m.slice(4, 6), 16),
    ];
  }

  private clamp01(v: number): number {
    return v < 0 ? 0 : v > 1 ? 1 : v;
  }
}
