import {
  ChangeDetectionStrategy,
  Component,
  computed,
  effect,
  input,
  output,
  signal,
} from '@angular/core';

export interface DateRange {
  start: string;
  end: string;
}

const MS_PER_DAY = 86_400_000;
const MAX_DAYS = 30;
const LOOKBACK_YEARS = 5;

@Component({
  selector: 'app-date-range-picker',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  templateUrl: './date-range-picker.component.html',
  styleUrl: './date-range-picker.component.css',
})
export class DateRangePickerComponent {
  /** Canonical applied range from the parent. */
  readonly start = input<string>('');
  readonly end = input<string>('');

  readonly rangeApply = output<DateRange>();

  // Draft (un-applied) values edited in the inputs.
  readonly draftStart = signal<string>('');
  readonly draftEnd = signal<string>('');

  readonly lookbackNote = `Data is available for the past ${LOOKBACK_YEARS} years only`;

  // Bounds for the native pickers — disables out-of-window dates instantly.
  readonly maxIso = this.toIso(new Date());
  readonly minIso = this.computeMinIso();

  readonly dayCount = computed(() => {
    const s = this.draftStart();
    const e = this.draftEnd();
    if (!s || !e) return 0;
    const diff = (Date.parse(e) - Date.parse(s)) / MS_PER_DAY;
    return Number.isFinite(diff) ? Math.round(diff) + 1 : 0;
  });

  /** Validation feedback is a pure computed → renders synchronously (<100ms). */
  readonly error = computed<string | null>(() => {
    const s = this.draftStart();
    const e = this.draftEnd();
    if (!s || !e) return null;
    if (Date.parse(e) < Date.parse(s)) {
      return 'End date must be on or after the start date';
    }
    if (this.dayCount() > MAX_DAYS) {
      return 'Date range must be 30 days or fewer';
    }
    return null;
  });

  readonly canApply = computed(
    () => !!this.draftStart() && !!this.draftEnd() && this.error() === null,
  );

  constructor() {
    // Keep the draft in sync when the parent changes the applied range.
    effect(() => {
      this.draftStart.set(this.start());
      this.draftEnd.set(this.end());
    });
  }

  onStart(event: Event): void {
    this.draftStart.set((event.target as HTMLInputElement).value);
  }

  onEnd(event: Event): void {
    this.draftEnd.set((event.target as HTMLInputElement).value);
  }

  apply(): void {
    if (this.canApply()) {
      this.rangeApply.emit({ start: this.draftStart(), end: this.draftEnd() });
    }
  }

  private computeMinIso(): string {
    const d = new Date();
    d.setFullYear(d.getFullYear() - LOOKBACK_YEARS);
    return this.toIso(d);
  }

  private toIso(d: Date): string {
    return d.toISOString().slice(0, 10);
  }
}
