import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
} from '@angular/core';

@Component({
  selector: 'app-playback-controls',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  templateUrl: './playback-controls.component.html',
  styleUrl: './playback-controls.component.css',
})
export class PlaybackControlsComponent {
  readonly isPlaying = input<boolean>(false);
  readonly currentIndex = input<number>(0);
  readonly totalFrames = input<number>(0);
  readonly speed = input<number>(2);
  readonly disabled = input<boolean>(false);

  readonly playToggle = output<void>();
  readonly stepForward = output<void>();
  readonly stepBackward = output<void>();
  readonly scrub = output<number>();
  readonly speedChange = output<number>();

  readonly speeds = [1, 2, 5, 10];

  readonly maxIndex = computed(() => Math.max(0, this.totalFrames() - 1));
  readonly atStart = computed(() => this.currentIndex() <= 0);
  readonly atEnd = computed(() => this.currentIndex() >= this.maxIndex());

  onScrub(event: Event): void {
    const value = Number((event.target as HTMLInputElement).value);
    this.scrub.emit(value);
  }

  onSpeed(event: Event): void {
    const value = Number((event.target as HTMLSelectElement).value);
    this.speedChange.emit(value);
  }
}
