import {
  ChangeDetectionStrategy,
  Component,
  OnDestroy,
  OnInit,
  computed,
  signal,
} from '@angular/core';
import { RouterLink } from '@angular/router';
import { Frame, VizMode } from '../core/models';
import { HeatmapCanvasComponent } from '../heatmap-canvas/heatmap-canvas.component';
import { LegendComponent } from '../legend/legend.component';
import { ModeToggleComponent } from '../mode-toggle/mode-toggle.component';
import { PlaybackControlsComponent } from '../playback-controls/playback-controls.component';
import {
  DateRangePickerComponent,
  DateRange,
} from '../date-range-picker/date-range-picker.component';

type LoadState = 'ready' | 'no-data' | 'error';

@Component({
  selector: 'app-visualization',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    RouterLink,
    HeatmapCanvasComponent,
    LegendComponent,
    ModeToggleComponent,
    PlaybackControlsComponent,
    DateRangePickerComponent,
  ],
  templateUrl: './visualization.component.html',
  styleUrl: './visualization.component.css',
})
export class VisualizationComponent implements OnInit, OnDestroy {
  /**
   * Loaded animation frames for the current (range, mode).
   * DATA CONTRACT: backend-provided — declared as an (initially empty) signal
   * so mockup_cleaner/service_agent can wire it to the frames API in ngOnInit.
   */
  readonly frames = signal<Frame[]>([]);

  readonly mode = signal<VizMode>('absolute');
  readonly currentIndex = signal<number>(0);
  readonly isPlaying = signal<boolean>(false);
  readonly speed = signal<number>(2);
  readonly state = signal<LoadState>('ready');

  /** degraded-performance response header — consumed silently (no error). */
  readonly degraded = signal<boolean>(false);

  readonly range = signal<DateRange>(this.defaultRange());

  private timer: ReturnType<typeof setInterval> | null = null;

  readonly totalFrames = computed(() => this.frames().length);
  readonly currentFrame = computed<Frame | null>(
    () => this.frames()[this.currentIndex()] ?? null,
  );
  readonly currentDateLabel = computed(() => {
    const f = this.currentFrame();
    return f ? this.formatDate(f.date) : '—';
  });

  ngOnInit(): void {
    this.loadAnimation(this.range());
  }

  ngOnDestroy(): void {
    this.stopTimer();
  }

  // --- loading -------------------------------------------------------------

  onRangeApply(range: DateRange): void {
    this.range.set(range);
    this.currentIndex.set(0);
    this.loadAnimation(range);
  }

  onModeChange(mode: VizMode): void {
    // Reload the same range in the new mode, resuming at the same frame index.
    const keepIndex = this.currentIndex();
    const wasPlaying = this.isPlaying();
    this.mode.set(mode);
    this.loadAnimation(this.range(), keepIndex);
    if (wasPlaying) {
      this.play();
    }
  }

  private loadAnimation(range: DateRange, resumeIndex = 0): void {
    this.pause();

    // Mock ingestion lag: data is available only up to two days ago.
    const latest = new Date();
    latest.setDate(latest.getDate() - 2);
    if (Date.parse(range.start) > latest.getTime()) {
      this.frames.set([]);
      this.state.set('no-data');
      return;
    }

    const built = this.buildMockFrames(range, this.mode());
    this.frames.set(built);
    this.state.set('ready');
    this.degraded.set(false);
    this.currentIndex.set(Math.min(resumeIndex, Math.max(0, built.length - 1)));
  }

  // --- playback ------------------------------------------------------------

  togglePlay(): void {
    this.isPlaying() ? this.pause() : this.play();
  }

  play(): void {
    if (this.totalFrames() === 0) return;
    this.isPlaying.set(true);
    this.restartTimer();
  }

  pause(): void {
    this.isPlaying.set(false);
    this.stopTimer();
  }

  stepForward(): void {
    this.pause();
    this.currentIndex.update((i) => Math.min(i + 1, this.totalFrames() - 1));
  }

  stepBackward(): void {
    this.pause();
    this.currentIndex.update((i) => Math.max(i - 1, 0));
  }

  onScrub(index: number): void {
    this.currentIndex.set(index);
  }

  onSpeedChange(fps: number): void {
    this.speed.set(fps);
    if (this.isPlaying()) {
      this.restartTimer();
    }
  }

  private restartTimer(): void {
    this.stopTimer();
    const interval = 1000 / this.speed();
    this.timer = setInterval(() => {
      const next = this.currentIndex() + 1;
      if (next >= this.totalFrames()) {
        this.currentIndex.set(0); // loop
      } else {
        this.currentIndex.set(next);
      }
    }, interval);
  }

  private stopTimer(): void {
    if (this.timer !== null) {
      clearInterval(this.timer);
      this.timer = null;
    }
  }

  // --- mock frame synthesis (replaced by the frames API downstream) --------

  /** Rough contiguous-US land mask (1 = land). */
  private static readonly US_MASK = [
    '000000000000000000000000000000',
    '000001111111111111111111110000',
    '000111111111111111111111111100',
    '011111111111111111111111111110',
    '111111111111111111111111111111',
    '111111111111111111111111111110',
    '011111111111111111111111111110',
    '001111111111111111111111111100',
    '000111111111111111111111111000',
    '000011111111111111111111110000',
    '000001111111111111111110000000',
    '000000111111111111111100000000',
    '000000011111111100111110000000',
    '000000000111110000001110000000',
    '000000000011000000000110000000',
  ];

  private buildMockFrames(range: DateRange, mode: VizMode): Frame[] {
    const days = this.daySpan(range);
    const mask = VisualizationComponent.US_MASK;
    const rows = mask.length;
    const cols = mask[0].length;
    const frames: Frame[] = [];

    for (let d = 0; d < days; d++) {
      const grid: (number | null)[] = new Array(rows * cols).fill(null);
      const confidence: number[] = new Array(rows * cols).fill(0);
      // A drifting warm front moves west→east across the days.
      const front = (d / Math.max(1, days - 1)) * cols;

      for (let r = 0; r < rows; r++) {
        for (let c = 0; c < cols; c++) {
          const idx = r * cols + c;
          if (mask[r][c] !== '1') continue;

          const yNorm = r / rows; // 0 north → 1 south
          const xNorm = c / cols;
          const wave =
            Math.sin((xNorm * 3 + d * 0.4) * Math.PI) * 6 +
            Math.cos((yNorm * 2 + d * 0.25) * Math.PI) * 5;

          let value: number;
          if (mode === 'absolute') {
            // Colder north, warmer south, plus the moving front and waves.
            const base = 26 + yNorm * 52;
            const frontWarmth = Math.max(0, 10 - Math.abs(c - front)) * 1.4;
            value = base + wave + frontWarmth;
          } else {
            // Departure from normal: centered near zero, banded by the front.
            const band = (c - front) / cols;
            value = band * 26 + wave * 0.9;
          }

          // Confidence: lower near the coastlines and in a sparse pocket.
          const edge = this.edgeProximity(mask, r, c);
          const sparsePocket =
            r > 9 && r < 13 && c > 6 && c < 11 && (d % 3 === 0);
          let conf = 0.55 + edge * 0.45;
          if (sparsePocket) conf = 0.3;
          confidence[idx] = Math.min(1, conf);
          grid[idx] = Math.round(value * 10) / 10;
        }
      }

      frames.push({
        date: this.addDaysIso(range.start, d),
        rows,
        cols,
        grid,
        confidence,
      });
    }
    return frames;
  }

  /** 0 at the mask edge, →1 deep in the interior (4-neighbour land count). */
  private edgeProximity(mask: string[], r: number, c: number): number {
    let land = 0;
    const offs = [
      [-1, 0],
      [1, 0],
      [0, -1],
      [0, 1],
    ];
    for (const [dr, dc] of offs) {
      const rr = r + dr;
      const cc = c + dc;
      if (
        rr >= 0 &&
        rr < mask.length &&
        cc >= 0 &&
        cc < mask[0].length &&
        mask[rr][cc] === '1'
      ) {
        land++;
      }
    }
    return land / offs.length;
  }

  // --- date helpers --------------------------------------------------------

  private defaultRange(): DateRange {
    const end = new Date();
    end.setDate(end.getDate() - 14);
    const start = new Date(end);
    start.setDate(start.getDate() - 13); // 14-day span
    return { start: this.toIso(start), end: this.toIso(end) };
  }

  private daySpan(range: DateRange): number {
    const diff =
      (Date.parse(range.end) - Date.parse(range.start)) / 86_400_000;
    return Math.max(1, Math.round(diff) + 1);
  }

  private addDaysIso(iso: string, days: number): string {
    const d = new Date(iso + 'T00:00:00');
    d.setDate(d.getDate() + days);
    return this.toIso(d);
  }

  private toIso(d: Date): string {
    return d.toISOString().slice(0, 10);
  }

  private formatDate(iso: string): string {
    const d = new Date(iso + 'T00:00:00');
    return d.toLocaleDateString('en-US', {
      weekday: 'short',
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  }
}
